spec.expr:
sum(count_over_time(
  {job="faro-web"} | json | kind="measurement" | type="web-vitals" | value_ttfb != "" [$__interval]
))

sum(
  count_over_time({job="faro-web"} | json | type=`http-status` | context_status =~ `^(0|[45]\d\d)$` [$__range])
)

topk(10,
  sum by (api_path, page_id) (
    count_over_time(
      {job="faro-web"} | json | kind=`event`
      | event_name=~`faro\.tracing\.fetch|faro\.tracing\.xml-http-request`
      [$__range]
    )
  )
)

count by () (
  sum by (session_id) (
    count_over_time(
      {job="faro-web"} | json | kind=`event`
      | event_name=~`session_start|session_extend|session_resume`
      | session_id != ``
      [$__auto]
    )
  )
)
